export function registeredSchemaRules(): readonly RegisteredSchemaRule[] {
  return RULES;
}

function schemaRuleIdentities(program: ArtifactSchemaProgram): readonly SchemaRuleIdentity[] {
  const identities: SchemaRuleIdentity[] = [];
  for (const schema of program.schemas.values()) {
    schema.crossFieldRules.forEach((text, occurrenceIndex) => {
      identities.push(Object.freeze({
        schemaId: schema.schemaId,
        collection: 'crossFieldRules' as const,
        occurrenceIndex,
        field: null,
        text,
      }));
    });
    for (const [field, text] of schema.arrayRules) {
      identities.push(Object.freeze({
        schemaId: schema.schemaId,
        collection: 'arrayRules' as const,
        occurrenceIndex: null,
        field,
        text,
      }));
    }
  }
  return Object.freeze(identities);
}

function modesAreCanonical(modes: readonly VerificationMode[]): boolean {
  return modes.length > 0 &&
    new Set(modes).size === modes.length &&
    modes.every((mode, index) => index === 0 ||
      VERIFICATION_MODE_ORDER.indexOf(modes[index - 1] as VerificationMode) <
        VERIFICATION_MODE_ORDER.indexOf(mode));
}

export function admitSchemaRuleRegistry(program: ArtifactSchemaProgram): void {
  const expected = schemaRuleIdentities(program);
  if (expected.length !== 171 || RULES.length !== 171) {
    throw new TypeError('Schema rule occurrence registry is incomplete.');
  }
  const expectedKeys = expected.map(ruleIdentityKey);
  const registeredKeys = RULES.map(ruleIdentityKey);
  if (
    new Set(expectedKeys).size !== expectedKeys.length ||
    new Set(registeredKeys).size !== registeredKeys.length ||
    expectedKeys.some((key, index) => key !== registeredKeys[index]) ||
    RULES.some((registered) => !modesAreCanonical(registered.verificationModes))
  ) {
    throw new TypeError('Schema rule occurrence registry differs from the frozen schema.');
  }
  const crossTexts = new Set(RULES.filter((entry) => entry.collection === 'crossFieldRules').map((entry) => entry.text));
  const arrayTexts = new Set(RULES.filter((entry) => entry.collection === 'arrayRules').map((entry) => entry.text));
  if (
    RULES.filter((entry) => entry.collection === 'crossFieldRules').length !== 153 ||
    RULES.filter((entry) => entry.collection === 'arrayRules').length !== 18 ||
    crossTexts.size !== 151 || arrayTexts.size !== 15 ||
    RULES.some((registered) =>
      !registeredRuleHasCanonicalEnforcementSites(registered))
  ) {
    throw new TypeError('Schema rule registry cardinalities differ from the frozen contract.');
  }
}
